var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"푸하아……!","JPN":"ぷはっ……！","ENG":"Puaah...!","TWN":"哇哈哈……！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…술이라는 건 기분이 참 좋군.","JPN":"……酒とはとても気持ちいいものだな。","ENG":"...Alcohol's pretty good, don't you think?","TWN":"…酒會讓人心情變好。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"어느 정도 예상은 했지만, 역시 미성년자셨군요.","JPN":"ある程度予想はしていましたが、やはり未成年者でしたか。","ENG":"I kind of expected it, but you're a minor...","TWN":"雖然有猜到，結果還真的未成年。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"웃기지 마라! 이래봬도 장교다! 성인이라고!","JPN":"ふざけるな！　こう見えても将校だ！　大人なんだ！","ENG":"Nuh-uh! I'm an adult! An officer!","TWN":"笑死啦！我可是軍官欸！我是大人！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"내가 술을 마시지 않았던 건 그저…","JPN":"私が酒を飲まなかったのはただ……","ENG":"I just don't drink because...","TWN":"我不喝酒只是…"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"남들에게 약한 모습을 보이기 싫었을 뿐이기 때문이다.","JPN":"人に弱い姿を見せたくなかっただけだ。","ENG":"I don't want people see me weak.","TWN":"因爲不想在別人面前，表現出軟弱的一面。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…장교님은 지금도 충분히 강해보이십니다.","JPN":"……将校は今でも十分強く見えます。","ENG":"...You don't look weak to me, Officer.","TWN":"…你現在看起來就已經很強啦。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흥, 뻔한 거짓말을.","JPN":"フン、白々しい嘘を。","ENG":"Hmph, again with your lies.","TWN":"哼，聽就知道是騙人的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"역시 티가 났습니까?","JPN":"やはり気付かれましたか。","ENG":"Did it show?","TWN":"有這麼明顯嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아부를 할 거면 제대로 해! 중간에 관두지 마!","JPN":"お世辞を言うならしっかり言え！　途中でやめるな！","ENG":"If you're going to flatter me, do it right! Don't give up halfway through!","TWN":"要拍馬屁就好好拍！不要中途放棄！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흥.","JPN":"フン。","ENG":"Hmpf.","TWN":"哼。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"내 아버지는 왕실 최고 기술자로서 폐하의 신임을 한몸에 받던 분이셨다.","JPN":"私の父は王室の最高技術者として陛下の信頼を一身に受けていた方だった。","ENG":"My father was once the Royal Chief Technician, and His Majesty had great faith in him.","TWN":"我父親是皇室頂尖技師，深受陛下信任。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"평민 출신임에도 방계 왕족이셨던 어머니와 혼사를 치를 정도였어.","JPN":"平民出身にも関わらず、傍系の王族だった母と結婚するくらいだったからな。","ENG":"Enough so that even being born a commoner, he got to marry royalty.","TWN":"雖然出身平民，卻還是和旁系皇族的母親結婚。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"하지만 아버지의 상관이 뒤집어쓴 오명 때문에, 우리 가문의 명예마저 바닥으로 실추하고 말았지.","JPN":"だが、父の上官が汚名を着せられたせいで、私の家門の名誉もまた失墜してしまったんだ。","ENG":"But due to my father's superior being branded as a traitor, our family's honor was ruined.","TWN":"只是因爲父親的上司的抹黑而蒙受污名，導致連我們家族的名譽掃地。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"가문의 명예를 다시 드높이고자 나 또한 최고가 되려 노력했지만…","JPN":"家門の名誉を再び高めようと、私もまた最高となるべく努力したが……","ENG":"I've tried my best to restore my family's honor, but...","TWN":"我很努力要成為頂尖，使家族能夠恢復的名聲……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"내가 아무리 노력해도, 오명의 멍에를 떨쳐내기엔 역부족이더군.","JPN":"いくら頑張っても、汚名という首枷から逃れるには力不足だった。","ENG":"No matter how hard I tried, it wasn't enough to wash off the shame.","TWN":"但不管我怎麼努力，就是無法擺脫污名的枷鎖。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래서 이곳에 오신 거군요.","JPN":"それでここにいらしたわけですか。","ENG":"So that's the real reason you're here.","TWN":"所以才來這裡嗎。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};